import React, { useState, useEffect } from "react";
import Header from "./components/Logo";
import Intro from "./Components/Intro";
import Login from "./Components/Login";

function App() {
  const [showLogin, setShowLogin] = useState(false);
  const [fadeOut, setFadeOut] = useState(false);

  useEffect(() => {
    const timer1 = setTimeout(() => setFadeOut(true), 2500); // 2.5 sec fade
    const timer2 = setTimeout(() => setShowLogin(true), 3500); // 3.5 sec Login
    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
    };
  }, []);

  return <div>{showLogin ? <Login /> : <Intro fadeOut={fadeOut} />}</div>;
}

export default App;
